import{_ as a,o as t,c as r,ag as l}from"./chunks/framework.DXGyWiRo.js";const i="/images/navi13.png?raw=true",m=JSON.parse('{"title":"13 如何设计一个Web框架","description":"","frontmatter":{},"headers":[],"relativePath":"13/0.md","filePath":"13/0.md","lastUpdated":null}'),o={name:"13/0.md"};function n(s,e,_,c,d,h){return t(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="_13-如何设计一个web框架" tabindex="-1">13 如何设计一个Web框架 <a class="header-anchor" href="#_13-如何设计一个web框架" aria-label="Permalink to &quot;13 如何设计一个Web框架&quot;">​</a></h1><p>前面十二章介绍了如何通过Go来开发Web应用，介绍了很多基础知识、开发工具和开发技巧，那么我们这一章通过这些知识来实现一个简易的Web框架。通过Go语言来实现一个完整的框架设计，这框架中主要内容有第一小节介绍的Web框架的结构规划，例如采用MVC模式来进行开发，程序的执行流程设计等内容；第二小节介绍框架的第一个功能：路由，如何让访问的URL映射到相应的处理逻辑；第三小节介绍处理逻辑，如何设计一个公共的controller，对象继承之后处理函数中如何处理response和request；第四小节介绍框架的一些辅助功能，例如日志处理、配置信息等；第五小节介绍如何基于Web框架实现一个博客，包括博文的发表、修改、删除、显示列表等操作。</p><p>通过这么一个完整的项目例子，我期望能够让读者了解如何开发Web应用，如何搭建自己的目录结构，如何实现路由，如何实现MVC模式等各方面的开发内容。在框架盛行的今天，MVC也不再是神话。经常听到很多程序员讨论哪个框架好，哪个框架不好， 其实框架只是工具，没有好与不好，只有适合与不适合，适合自己的就是最好的，所以教会大家自己动手写框架，那么不同的需求都可以用自己的思路去实现。</p><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><p><img src="'+i+'" alt=""></p><h2 id="links" tabindex="-1">links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links&quot;">​</a></h2><ul><li><a href="/">目录</a></li><li>上一章: <a href="/12/5.html">第十二章总结</a></li><li>下一节: <a href="/13/1.html">项目规划</a></li></ul>',7)])])}const b=a(o,[["render",n]]);export{m as __pageData,b as default};
